    "data:image/png;base64,";
export const BAG_MARK_ASPECT = 1.0228; // w/h

/** The full "Hack Club Shop" wordmark (bag + text). Wide — for larger labels. */
export const WORDMARK_DATA_URI =
    "data:image/png;base64,";
